import React from 'react'

export default function Info(props) {
  return (
<tr>
      {props.players.map((i) => { return <tr>
            <th>{i.name}</th>
            <th>{i.games}</th>
            <th>{i.winnings}</th> </tr> })}
            </tr>
  )
}
